  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { useTheme } from 'storybook/internal/theming';
  5→import { EVENTS } from './constants';
  6→import { useIndexedDB } from './useIndexedDB';
  7→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  8→import JSON5 from 'json5';
  9→
 10→function idbKeyFor(storyId: string) {
 11→  return `sdui-json-${storyId}`;
 12→}
 13→
 14→function getChannel() {
 15→  try { return addons.getChannel(); } catch { return null; }
 16→}
 17→
 18→function tryParse(text: string): { parsed: any; error: string | null } {
 19→  try {
 20→    return { parsed: JSON.parse(text), error: null };
 21→  } catch {
 22→    try {
 23→      return { parsed: JSON5.parse(text), error: null };
 24→    } catch (e) {
 25→      return { parsed: null, error: (e as Error).message };
 26→    }
 27→  }
 28→}
 29→
 30→export function JsonEditorPanel() {
 31→  const state = useStorybookState();
 32→  const storyId = state.storyId ?? '';
 33→  const theme = useTheme();
 34→  const isDarkMode = theme.base === 'dark';
 35→
 36→  const [defaultJson, setDefaultJson] = useState<string>('');
 37→  const [text, setText] = useState<string>('');
 38→  const [error, setError] = useState<string | null>(null);
 39→  const [dirty, setDirty] = useState(false);
 40→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 41→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 42→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 43→
 44→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 45→
 46→  useEffect(() => {
 47→    return () => {
 48→      if (debounceRef.current) clearTimeout(debounceRef.current);
 49→      if (retryRef.current) clearInterval(retryRef.current);
 50→    };
 51→  }, []);
 52→
 53→  useEffect(() => {
 54→    if (debounceRef.current) {
 55→      clearTimeout(debounceRef.current);
 56→      debounceRef.current = null;
 57→    }
 58→    setDefaultJson('');
 59→    setError(null);
 60→  }, [storyId]);
 61→
 62→  useEffect(() => {
 63→    const channel = getChannel();
 64→    if (!channel) return;
 65→
 66→    const onSetDefault = (json: string) => {
 67→      setDefaultJson(json);
 68→      if (retryRef.current) {
 69→        clearInterval(retryRef.current);
 70→        retryRef.current = null;
 71→      }
 72→    };
 73→
 74→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 75→    channel.emit(EVENTS.REQUEST_DEFAULT);
 76→
 77→    let retryCount = 0;
 78→    retryRef.current = setInterval(() => {
 79→      retryCount++;
 80→      if (retryCount > 20) {
 81→        if (retryRef.current) clearInterval(retryRef.current);
 82→        return;
 83→      }
 84→      channel.emit(EVENTS.REQUEST_DEFAULT);
 85→    }, 250);
 86→
 87→    return () => {
 88→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 89→      if (retryRef.current) {
 90→        clearInterval(retryRef.current);
 91→        retryRef.current = null;
 92→      }
 93→    };
 94→  }, [storyId]);
 95→
 96→  useEffect(() => {
 97→    if (!ready || !defaultJson) return;
 98→    const initial = stored ?? defaultJson;
 99→    setText(initial);
100→    editorRef.current?.setValue(initial);
101→    setDirty(!!stored);
102→    setError(null);
103→  }, [ready, stored, defaultJson, storyId]);
104→
105→  const handleChange = useCallback(
106→    (value: string) => {
107→      setText(value);
108→
109→      if (debounceRef.current) clearTimeout(debounceRef.current);
110→
111→      debounceRef.current = setTimeout(() => {
112→        const { parsed, error: parseErr } = tryParse(value);
113→        if (parsed !== null) {
114→          save(value);
115→          setDirty(true);
116→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
117→        } else {
118→          save(value);
119→          setDirty(true);
120→        }
121→      }, 400);
122→    },
123→    [save],
124→  );
125→
126→  const handleValidationChange = useCallback(
127→    (hasErrors: boolean, message: string | null) => {
128→      setError(hasErrors ? message : null);
129→    },
130→    [],
131→  );
132→
133→  const handleReset = useCallback(() => {
134→    remove();
135→    setText(defaultJson);
136→    editorRef.current?.setValue(defaultJson);
137→    setDirty(false);
138→    setError(null);
139→    const { parsed } = tryParse(defaultJson);
140→    if (parsed !== null) {
141→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
142→    }
143→  }, [defaultJson, remove]);
144→
145→  const handleFormat = useCallback(() => {
146→    const currentText = editorRef.current?.getValue() ?? '';
147→    const { parsed, error: parseErr } = tryParse(currentText);
148→    if (parsed !== null) {
149→      const formatted = JSON.stringify(parsed, null, 2);
150→      setText(formatted);
151→      editorRef.current?.setValue(formatted);
152→      save(formatted);
153→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
154→      setError(null);
155→    } else {
156→      setError(parseErr);
157→    }
158→  }, [save]);
159→
160→  const s = isDarkMode ? darkStyles : lightStyles;
161→
162→  if (!storyId) {
163→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
164→  }
165→
166→  const isWaiting = !defaultJson && !text;
167→
168→  return (
169→    <div style={s.container}>
170→      <div style={s.toolbar}>
171→        <span style={s.label}>
172→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
173→        </span>
174→        <div style={s.actions}>
175→          <button
176→            style={s.btn}
177→            onClick={handleFormat}
178→            title="Format JSON (normalizes to strict JSON)"
179→          >
180→            Format
181→          </button>
182→          <button
183→            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
184→            onClick={handleReset}
185→            disabled={!dirty}
186→            title="Reset to story default"
187→          >
188→            Reset
189→          </button>
190→        </div>
191→      </div>
192→
193→      {error && !isWaiting && <div style={s.error}>{error}</div>}
194→
195→      {isWaiting ? (
196→        <div style={s.empty}>
197→          Waiting for story to send SDUI JSON…
198→          <br />
199→          <span style={{ fontSize: 11, opacity: 0.7 }}>
200→            If this persists, the current story may not use useSDUIJsonEditor().
201→          </span>
202→        </div>
203→      ) : (
204→        <div style={s.editorContainer}>
205→          <CodeMirrorEditor
206→            ref={editorRef}
207→            value={text}
208→            onChange={handleChange}
209→            onValidationChange={handleValidationChange}
210→            isDarkMode={isDarkMode}
211→          />
212→        </div>
213→      )}
214→    </div>
215→  );
216→}
