  1→import Ajv from 'ajv';
  2→import JSON5 from 'json5';
  3→import type { Diagnostic } from '@codemirror/lint';
  4→import type { EditorView } from '@codemirror/view';
  5→import { sduiScreenSchema, knownTypes, componentPropsSchemas } from './sduiSchema';
  6→
  7→const ajv = new Ajv({ allErrors: true, verbose: true, strict: false });
  8→const validate = ajv.compile(sduiScreenSchema);
  9→
 10→function didYouMean(input: string, candidates: string[]): string | null {
 11→  let best: string | null = null;
 12→  let bestDist = Infinity;
 13→
 14→  for (const candidate of candidates) {
 15→    const dist = levenshtein(input.toLowerCase(), candidate.toLowerCase());
 16→    if (dist < bestDist && dist <= Math.max(2, Math.floor(input.length / 2))) {
 17→      bestDist = dist;
 18→      best = candidate;
 19→    }
 20→  }
 21→  return best;
 22→}
 23→
 24→function levenshtein(a: string, b: string): number {
 25→  const m = a.length;
 26→  const n = b.length;
 27→  const dp: number[][] = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
 28→
 29→  for (let i = 0; i <= m; i++) dp[i][0] = i;
 30→  for (let j = 0; j <= n; j++) dp[0][j] = j;
 31→
 32→  for (let i = 1; i <= m; i++) {
 33→    for (let j = 1; j <= n; j++) {
 34→      dp[i][j] = a[i - 1] === b[j - 1]
 35→        ? dp[i - 1][j - 1]
 36→        : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
 37→    }
 38→  }
 39→  return dp[m][n];
 40→}
 41→
 42→function findJsonPath(doc: string, path: string): { from: number; to: number } | null {
 43→  const segments = path.split('/').filter(Boolean);
 44→  let pos = 0;
 45→
 46→  for (const seg of segments) {
 47→    const isIndex = /^\d+$/.test(seg);
 48→
 49→    if (isIndex) {
 50→      const idx = parseInt(seg, 10);
 51→      let bracketDepth = 0;
 52→      let currentIdx = -1;
 53→      const arrStart = doc.indexOf('[', pos);
 54→      if (arrStart === -1) return null;
 55→      pos = arrStart + 1;
 56→
 57→      while (pos < doc.length && currentIdx < idx) {
 58→        const ch = doc[pos];
 59→        if (ch === '[' || ch === '{') bracketDepth++;
 60→        else if (ch === ']' || ch === '}') bracketDepth--;
 61→        else if (ch === ',' && bracketDepth === 0) currentIdx++;
 62→        else if (bracketDepth === 0 && /[^\s,]/.test(ch) && currentIdx < idx) {
 63→          if (currentIdx === -1) currentIdx = 0;
 64→          if (currentIdx === idx) break;
 65→        }
 66→        if (bracketDepth < 0) break;
 67→        pos++;
 68→      }
 69→
 70→      if (currentIdx < idx - 1) {
 71→        const lastBrace = doc.lastIndexOf('{', pos);
 72→        if (lastBrace >= arrStart) pos = lastBrace;
 73→      }
 74→    } else {
 75→      const escaped = seg.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
 76→      const keyPattern = new RegExp(`(?:"${escaped}"|${escaped})\\s*:`);
 77→      const match = keyPattern.exec(doc.slice(pos));
 78→      if (!match) return null;
 79→      pos += match.index;
 80→    }
 81→  }
 82→
 83→  let lineEnd = doc.indexOf('\n', pos);
 84→  if (lineEnd === -1) lineEnd = doc.length;
 85→
 86→  return { from: pos, to: Math.min(pos + 40, lineEnd) };
 87→}
 88→
 89→function humanizeMessage(error: Ajv.ErrorObject): string {
 90→  const { keyword, params, instancePath, message } = error;
 91→
 92→  if (keyword === 'enum' && instancePath.endsWith('/type')) {
 93→    const value = (error as any).data;
 94→    if (typeof value === 'string') {
 95→      const suggestion = didYouMean(value, [...knownTypes]);
 96→      const base = `Unknown component type "${value}"`;
 97→      return suggestion ? `${base} — did you mean "${suggestion}"?` : `${base}. Valid types: ${knownTypes.join(', ')}`;
 98→    }
 99→  }
100→
101→  if (keyword === 'required') {
102→    const missing = (params as any).missingProperty;
103→    return `Missing required property "${missing}"`;
104→  }
105→
106→  if (keyword === 'additionalProperties') {
107→    const extra = (params as any).additionalProperty;
108→    return `Unknown property "${extra}"`;
109→  }
110→
111→  if (keyword === 'type') {
112→    const expected = (params as any).type;
113→    return `Expected ${expected}${message ? ` — ${message}` : ''}`;
114→  }
115→
116→  if (keyword === 'const') {
117→    return `Expected value: ${JSON.stringify((params as any).allowedValue)}`;
118→  }
119→
120→  return message || 'Schema validation error';
121→}
122→
123→function validateComponentProps(parsed: any, doc: string): Diagnostic[] {
124→  const diagnostics: Diagnostic[] = [];
125→
126→  const components: Array<{ component: any; path: string }> = [];
127→
128→  if (parsed.header) components.push({ component: parsed.header, path: '/header' });
129→  if (parsed.footer) components.push({ component: parsed.footer, path: '/footer' });
130→  if (Array.isArray(parsed.body)) {
131→    parsed.body.forEach((c: any, i: number) => components.push({ component: c, path: `/body/${i}` }));
132→  }
133→
134→  for (const { component, path } of components) {
135→    const type = component?.type;
136→    if (!type || typeof type !== 'string') continue;
137→
138→    if (!knownTypes.includes(type as any)) {
139→      const suggestion = didYouMean(type, [...knownTypes]);
140→      const loc = findJsonPath(doc, `${path}/type`);
141→      const msg = suggestion
142→        ? `Unknown component type "${type}" — did you mean "${suggestion}"?`
143→        : `Unknown component type "${type}". Valid: ${knownTypes.join(', ')}`;
144→      diagnostics.push({
145→        from: loc?.from ?? 0,
146→        to: loc?.to ?? 0,
147→        severity: 'warning',
148→        message: msg,
149→        source: 'sdui-schema',
150→      });
151→      continue;
152→    }
153→
154→    const propsSchema = componentPropsSchemas[type] as any;
155→    if (!propsSchema) continue;
156→
157→    const required: string[] = propsSchema.required || [];
158→    const props = component.props || {};
159→    const knownProps = Object.keys(propsSchema.properties || {});
160→
161→    for (const req of required) {
162→      if (props[req] === undefined || props[req] === null) {
163→        const loc = findJsonPath(doc, `${path}/props`);
164→        diagnostics.push({
165→          from: loc?.from ?? 0,
166→          to: loc?.to ?? 0,
167→          severity: 'error',
168→          message: `"${type}" requires property "${req}"`,
169→          source: 'sdui-schema',
170→        });
171→      }
172→    }
173→
174→    for (const propName of Object.keys(props)) {
175→      if (!knownProps.includes(propName)) {
176→        const suggestion = didYouMean(propName, knownProps);
177→        const loc = findJsonPath(doc, `${path}/props/${propName}`);
178→        const msg = suggestion
179→          ? `Unknown prop "${propName}" on "${type}" — did you mean "${suggestion}"?`
180→          : `Unknown prop "${propName}" on "${type}". Valid: ${knownProps.join(', ')}`;
181→        diagnostics.push({
182→          from: loc?.from ?? 0,
183→          to: loc?.to ?? 0,
184→          severity: 'warning',
185→          message: msg,
186→          source: 'sdui-schema',
187→        });
188→      }
189→    }
190→  }
191→
192→  return diagnostics;
193→}
194→
195→export function validateSduiJson(doc: string): Diagnostic[] {
196→  let parsed: any;
197→
198→  try {
199→    parsed = JSON.parse(doc);
200→  } catch {
201→    try {
202→      parsed = JSON5.parse(doc);
203→    } catch {
204→      return [];
205→    }
206→  }
207→
208→  if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
209→    return [{
210→      from: 0,
211→      to: Math.min(doc.length, 1),
212→      severity: 'error',
213→      message: 'SDUI screen must be a JSON object',
214→      source: 'sdui-schema',
215→    }];
216→  }
217→
218→  const diagnostics: Diagnostic[] = [];
219→
220→  validate(parsed);
221→  if (validate.errors) {
222→    for (const error of validate.errors) {
223→      if (error.keyword === 'if') continue;
224→
225→      const jsonPath = error.instancePath || '';
226→      const loc = findJsonPath(doc, jsonPath);
227→      const msg = humanizeMessage(error);
228→
229→      diagnostics.push({
230→        from: loc?.from ?? 0,
231→        to: loc?.to ?? 0,
232→        severity: error.keyword === 'required' || error.keyword === 'type' ? 'error' : 'warning',
233→        message: msg,
234→        source: 'sdui-schema',
235→      });
236→    }
237→  }
238→
239→  diagnostics.push(...validateComponentProps(parsed, doc));
240→
241→  const seen = new Set<string>();
242→  return diagnostics.filter(d => {
243→    const key = `${d.from}:${d.message}`;
244→    if (seen.has(key)) return false;
245→    seen.add(key);
246→    return true;
247→  });
248→}
249→
250→export function sduiSchemaLinter(view: EditorView): Diagnostic[] {
251→  return validateSduiJson(view.state.doc.toString());
252→}
