 6→export function useSDUIJsonEditor(defaultScreen: SDUIScreen): SDUIScreen {
 7→  const [screen, setScreen] = useState<SDUIScreen>(defaultScreen);
 8→  const defaultRef = useRef(defaultScreen);
 9→  defaultRef.current = defaultScreen;
10→
11→  useEffect(() => {
12→    setScreen(defaultScreen);
13→  }, [defaultScreen]);
14→
15→  useEffect(() => {
16→    const channel = addons.getChannel();
17→
18→    const onUpdate = (json: SDUIScreen) => {
19→      setScreen(json);
20→    };
21→
22→    const onRequestDefault = () => {
23→      channel.emit(
24→        EVENTS.SET_DEFAULT_JSON,
25→        JSON.stringify(defaultRef.current, null, 2),
26→      );
27→    };
28→
29→    channel.on(EVENTS.UPDATE_JSON, onUpdate);
30→    channel.on(EVENTS.REQUEST_DEFAULT, onRequestDefault);
31→
32→    channel.emit(
33→      EVENTS.SET_DEFAULT_JSON,
34→      JSON.stringify(defaultRef.current, null, 2),
35→    );
36→
37→    return () => {
38→      channel.off(EVENTS.UPDATE_JSON, onUpdate);
39→      channel.off(EVENTS.REQUEST_DEFAULT, onRequestDefault);
40→    };
41→  }, []);
42→
43→  return screen;
44→}
